def pushd(dir):
    orig = os.getcwd()
    os.chdir(dir)
# WARNING: Decompyle incomplete

pushd = contextlib.contextmanager(pushd)

def tarball_context(url, target_dir, runner, pushd = (None, None, pushd)):
    '''
    Get a tarball, extract it, change to that directory, yield, then
    clean up.
    `runner` is the function to invoke commands.
    `pushd` is a context manager for changing the directory.
    '''
    if target_dir is None:
        target_dir = os.path.basename(url).replace('.tar.gz', '').replace('.tgz', '')
    if runner is None:
        runner = functools.partial(subprocess.check_call, True, **('shell',))
# WARNING: Decompyle incomplete

tarball_context = contextlib.contextmanager(tarball_context)

def infer_compression(url):
    '''
    Given a URL or filename, infer the compression code for tar.
    '''
    compression_indicator = url[-2:]
    mapping = dict('z', 'j', 'J', **('gz', 'bz', 'xz'))
    return mapping.get(compression_indicator, 'z')


def temp_dir(remover = (shutil.rmtree,)):
    '''
    Create a temporary directory context. Pass a custom remover
    to override the removal behavior.
    '''
    temp_dir = tempfile.mkdtemp()
# WARNING: Decompyle incomplete

temp_dir = contextlib.contextmanager(temp_dir)

